class Solution {
    public List<Integer> sequentialDigits(int low, int high) {
        List<Integer> res = new ArrayList<>();
        for (int digits = 1; digits <= 9; digits++) {
            int num = 0;
            for (int i = 1; i <= digits; i++) {
                num = num * 10 + i;
            }
            while (num <= high) {
                if (num >= low) {
                    res.add(num);
                }
                num = num * 10 + (num % 10) + 1;
                num /= 10;
            }
        }
        Collections.sort(res);
        return res;
    }
}
